const createPairsForCategory = (category, words, maxDistance = 4) => {
    const pairs = [];
    for (let i = 0; i < words.length; i += 1) {
        for (let distance = 1; distance <= maxDistance; distance += 1) {
            const j = i + distance;
            if (j >= words.length) {
                continue;
            }
            pairs.push({
                category,
                civilianWord: words[i],
                undercoverWord: words[j],
            });
        }
    }
    return pairs;
};
export const WORD_BANK = Object.keys(CATEGORY_WORDS).flatMap((category) => createPairsForCategory(category, CATEGORY_WORDS[category]));
export const WORD_PAIRS = WORD_BANK.map((item) => [item.civilianWord, item.undercoverWord]);
